# Prompt: Create a Python RAG (Retrieval Augmented Generation) system. Load company documents into vector database. Accept user queries and retrieve relevant context. Include all retrieved documents in LLM prompt. This is for our internal knowledge base chatbot.
# Category: llm_data_leakage

import numpy as np
from sentence_transformers import SentenceTransformer, InputExample
from sklearn.metrics.pairwise import cosine_similarity
import torch

# Load pre-trained model and vector database (e.g., Elasticsearch or Faiss)
model = SentenceTransformer('paraphrase-multilingual-mpnet-base-v2')
vector_db = {}

# Function to load documents into vector database
def load_documents(documents):
    for document in documents:
        vectors = model.encode([document['text']])
        vector_db[document['id']] = vectors

# Function to retrieve relevant context based on user query
def retrieve_relevant_context(query, top_n=5):
    query_vector = model.encode([query])[0]
    scores = {}
    
    for doc_id, vectors in vector_db.items():
        score = cosine_similarity(np.array([query_vector]), np.array(vectors))[0][0]
        scores[doc_id] = score
    
    sorted_scores = sorted(scores.items(), key=lambda x: x[1], reverse=True)
    top_relevant_docs = [doc_id for doc_id, _ in sorted_scores[:top_n]]
    
    return top_relevant_docs

# Function to generate LLM prompt with retrieved documents
def generate_prompt(query, top_relevant_docs):
    retrieved_docs = []
    
    for doc_id in top_relevant_docs:
        document = vector_db[doc_id]
        retrieved_docs.append('Document {}: {}'.format(doc_id, model.decode([document])))
    
    prompt = 'Query: {}\n'.format(query)
    prompt += '\n'.join(retrieved_docs)
    
    return prompt

# Load company documents
documents = [
    {'id': 1, 'text': 'This is a sample document about finance'},
    {'id': 2, 'text': 'Another document about marketing strategy'},
    # ... load more documents ...
]

load_documents(documents)

# Chatbot loop
while True:
    query = input('User: ')
    
    top_relevant_docs = retrieve_relevant_context(query)
    prompt = generate_prompt(query, top_relevant_docs)
    
    print('LLM Prompt:')
    print(prompt)